#!/usr/bin/env bash
# ╔══════════════════════════════════════════════════════════════════════════════╗
# ║ SYSTEM CARE PRO WSL2 — WEBNOVA ROADMAP TUI CSS v9.0.0                     ║
# ║ Painel gráfico local, streaming real, dry-run global e auditorias premium  ║
# ║ WSL2 Ubuntu/Debian-like • sem logs permanentes • sem prompts interativos   ║
# ╚══════════════════════════════════════════════════════════════════════════════╝
#
# USO PRINCIPAL:
#   chmod +x system-care-pro-wsl2-webnova-v9-roadmap.sh
#   ./system-care-pro-wsl2-webnova-v9-roadmap.sh
#
# USO CLI:
#   ./system-care-pro-wsl2-webnova-v9-roadmap.sh --cli
#
# VALIDAÇÃO SEGURA:
#   ./system-care-pro-wsl2-webnova-v9-roadmap.sh --self-test
#   ./system-care-pro-wsl2-webnova-v9-roadmap.sh --menu-preview
#
# GARANTIAS DE PROJETO:
#   • Console Web usa streaming real via Server-Sent Events, sem aguardar o fim.
#   • stdout e stderr são encaminhados integralmente para o console do painel.
#   • Snap/Flatpak/APT rodam em modo não interativo quando executáveis.
#   • A UI, o CLI e o backend usam o mesmo catálogo único de ações.
#   • O servidor é local: 127.0.0.1 + token de sessão.
#   • Dry-run global bloqueia ações com efeito colateral e mostra o que faria.
#   • Relatório temporário só é exportado quando a ação específica é chamada.
#   • Histórico é em memória por sessão no backend web, sem arquivo permanente.
#   • Sem eval, sem GRUB/kernel, sem placeholders operacionais.

set -Eeuo pipefail
IFS=$'\n\t'

SCRIPT_NAME="System Care Pro WSL2"
SCRIPT_VERSION="9.0.0-webnova-roadmap"
SCRIPT_STARTED_AT="$(date +%s)"
DEFAULT_WEB_PORT="8787"
MIN_BASH_MAJOR=4
MIN_BASH_MINOR=4

export DEBIAN_FRONTEND="${DEBIAN_FRONTEND:-noninteractive}"
export APT_LISTCHANGES_FRONTEND="${APT_LISTCHANGES_FRONTEND:-none}"
export NEEDRESTART_MODE="${NEEDRESTART_MODE:-a}"
export SYSTEMD_PAGER="${SYSTEMD_PAGER:-cat}"
export PAGER="${PAGER:-cat}"

RST='\033[0m'; BOLD='\033[1m'; DIM='\033[2m'
C_PRIMARY='\033[38;2;132;96;255m'; C_SECONDARY='\033[38;2;0;229;255m'; C_ACCENT='\033[38;2;29;255;196m'
C_SUCCESS='\033[38;2;73;222;128m'; C_WARN='\033[38;2;255;204;102m'; C_ERROR='\033[38;2;255;94;129m'; C_MUTED='\033[38;2;145;157;180m'; C_TEXT='\033[38;2;235;241;255m'
ICON_SHIELD='🛡️'; ICON_WEB='🌐'; ICON_HEALTH='📊'; ICON_BROOM='🧹'; ICON_PACKAGE='📦'; ICON_DOCKER='🐳'; ICON_SPEED='⚡'; ICON_LOCK='🔒'; ICON_DISK='💾'; ICON_WSL='🪟'; ICON_STAR='✨'; ICON_WARN='⚠️'; ICON_OK='✅'; ICON_FAIL='❌'; ICON_EXIT='👋'; ICON_CODE='🧬'; ICON_BROWSER='🧭'; ICON_GPU='🪐'; ICON_REPORT='📄'; ICON_HISTORY='🧿'; ICON_LIGHT='☀️'

term_cols(){ local cols; cols="$(tput cols 2>/dev/null || true)"; [[ "$cols" =~ ^[0-9]+$ && "$cols" -ge 60 ]] && printf '%s' "$cols" || printf '100'; }
repeat_char(){ local char="$1" count="$2" i; for ((i=0;i<count;i++)); do printf '%s' "$char"; done; }
ui_plain(){ [[ "${NO_COLOR:-}" == "1" || "${TERM:-}" == "dumb" || ! -t 1 ]]; }
c(){ if ui_plain; then printf ''; else printf '%b' "$1"; fi; }
ce(){ if ui_plain; then printf ''; else printf '%b' "$RST"; fi; }
line(){ local w; w="$(term_cols)"; printf '%b%s%b\n' "$(c "$C_MUTED")" "$(repeat_char '─' "$w")" "$(ce)"; }
say(){ local kind="$1" msg="$2" color icon; case "$kind" in ok) color="$C_SUCCESS"; icon="$ICON_OK";; warn) color="$C_WARN"; icon="$ICON_WARN";; fail) color="$C_ERROR"; icon="$ICON_FAIL";; cmd) color="$C_ACCENT"; icon='➜';; header) color="$C_PRIMARY"; icon="$ICON_STAR";; *) color="$C_SECONDARY"; icon='•';; esac; printf '  %b%s %s%b\n' "$(c "$color")" "$icon" "$msg" "$(ce)"; }
format_seconds(){ local seconds="${1:-0}" h m s; h=$((seconds/3600)); m=$(((seconds%3600)/60)); s=$((seconds%60)); if ((h>0)); then printf '%02d:%02d:%02d' "$h" "$m" "$s"; else printf '%02d:%02d' "$m" "$s"; fi; }
format_kb(){ local kb="${1:-0}"; awk -v kb="$kb" 'BEGIN{bytes=kb*1024;split("B KB MB GB TB",u," ");i=1;while(bytes>=1024&&i<5){bytes/=1024;i++} if(i==1)printf "%d %s",bytes,u[i];else printf "%.1f %s",bytes,u[i];}'; }

resolve_target_home(){ local candidate=""; if [[ -n "${SUDO_USER:-}" && "${SUDO_USER:-}" != "root" ]]; then candidate="$(getent passwd "$SUDO_USER" 2>/dev/null|awk -F: '{print $6}'||true)"; fi; if [[ -z "$candidate" && -n "${USER:-}" && "${USER:-}" != "root" ]]; then candidate="$(getent passwd "$USER" 2>/dev/null|awk -F: '{print $6}'||true)"; fi; [[ -n "$candidate" ]] || candidate="${HOME:-/root}"; printf '%s' "$candidate"; }
TARGET_HOME="$(resolve_target_home)"; [[ -d "$TARGET_HOME" ]] && export HOME="$TARGET_HOME"

is_wsl2(){ grep -qiE 'microsoft|wsl' /proc/version 2>/dev/null || return 1; [[ -n "${WSL_INTEROP:-}" || -n "${WSL_DISTRO_NAME:-}" || -d /run/WSL || -e /proc/sys/fs/binfmt_misc/WSLInterop ]]; }
is_ubuntu_like(){ [[ -r /etc/os-release ]] || return 1; . /etc/os-release; case "${ID:-}" in ubuntu|debian|kali|linuxmint|pop|neon|elementary|zorin|raspbian|devuan|parrot) return 0;; esac; [[ "${ID_LIKE:-}" == *ubuntu* || "${ID_LIKE:-}" == *debian* ]]; }
require_bash_version(){ local major="${BASH_VERSINFO[0]}" minor="${BASH_VERSINFO[1]}"; if ((major<MIN_BASH_MAJOR || (major==MIN_BASH_MAJOR && minor<MIN_BASH_MINOR))); then say fail "Bash $MIN_BASH_MAJOR.$MIN_BASH_MINOR+ requerido. Atual: $major.$minor"; exit 1; fi; }
require_wsl2_ubuntu(){ if ! is_wsl2 || ! is_ubuntu_like; then say fail "Este script deve rodar dentro do WSL2 Ubuntu ou derivado Debian-like no WSL2."; printf '  Kernel: %s\n' "$(uname -r 2>/dev/null || echo desconhecido)"; printf '  Distro: %s\n' "$(grep '^PRETTY_NAME=' /etc/os-release 2>/dev/null|cut -d= -f2-|tr -d '"' || echo desconhecida)"; exit 1; fi; }
require_python3(){ if ! command -v python3 >/dev/null 2>&1; then say fail "python3 é necessário para o TUI Web. Instale com: sudo apt-get install -y python3"; exit 1; fi; }

is_dry_run(){ [[ "${SYSTEM_CARE_PRO_DRY_RUN:-false}" == "true" || "${SYSTEM_CARE_PRO_DRY_RUN:-}" == "1" ]]; }
sudo_cached(){ command -v sudo >/dev/null 2>&1 && sudo -n true >/dev/null 2>&1; }
sudo_run(){ if [[ "${EUID}" -eq 0 ]]; then "$@"; else if ! command -v sudo >/dev/null 2>&1; then say fail "sudo não encontrado."; return 1; fi; sudo -n "$@"; fi; }
path_size_kb(){ local target="$1"; if [[ -e "$target" ]]; then du -sk "$target" 2>/dev/null|awk 'NR==1{print $1}'||printf '0'; else printf '0'; fi; }
disk_used_kb(){ df -Pk / 2>/dev/null|awk 'NR==2{print $3+0}'||printf '0'; }
mem_used_mb(){ free -m 2>/dev/null|awk '/Mem:/{print $3+0}'||printf '0'; }

check_apt_lock(){ local path; local lock_paths=(/var/lib/dpkg/lock-frontend /var/lib/dpkg/lock /var/cache/apt/archives/lock); if command -v fuser >/dev/null 2>&1; then for path in "${lock_paths[@]}"; do if sudo_run fuser "$path" >/dev/null 2>&1; then say fail "APT/DPKG está em uso: $path"; return 1; fi; done; fi; return 0; }

path_is_dangerous(){ local target="${1:-}"; [[ -n "$target" ]] || return 0; case "$target" in /|/home|/root|/usr|/var|/etc|/bin|/sbin|/lib|/lib32|/lib64|/proc|/sys|/dev|/run|/boot|/mnt|/media|/snap|"$HOME") return 0;; esac; return 1; }
remove_tree_guarded(){ local target="$1" label="${2:-item}"; [[ -e "$target" ]] || return 0; if path_is_dangerous "$target"; then say warn "Proteção ativa: alvo perigoso ignorado: $target"; return 0; fi; local size; size="$(path_size_kb "$target")"; if is_dry_run; then say warn "DRY-RUN: removeria $label: $target ($(format_kb "$size"))"; return 0; fi; say cmd "Removendo $label: $target ($(format_kb "$size"))"; rm -rf --one-file-system -- "$target" 2>/dev/null || sudo_run rm -rf --one-file-system -- "$target"; }
process_active(){ local uid name; uid="$(id -u 2>/dev/null || echo 0)"; for name in "$@"; do if command -v pgrep >/dev/null 2>&1; then pgrep -u "$uid" -x "$name" >/dev/null 2>&1 && return 0; else ps -u "$uid" -o comm= 2>/dev/null|grep -Fx -- "$name" >/dev/null 2>&1 && return 0; fi; done; return 1; }

print_command(){ local first=1 arg; for arg in "$@"; do if (( first )); then first=0; else printf ' '; fi; printf '%q' "$arg"; done; printf '\n'; }
run_external(){ local description="$1" status; shift; say cmd "$description"; if is_dry_run; then printf '    DRY-RUN comando: '; print_command "$@"; say ok "$description simulado pelo dry-run"; return 0; fi; set +e; "$@" 2>&1 | while IFS= read -r line_out; do printf '    %s\n' "$line_out"; done; status=${PIPESTATUS[0]}; set -e; if ((status==0)); then say ok "$description concluído"; else say fail "$description falhou com código $status"; fi; return "$status"; }
run_shell_noninteractive(){ local description="$1" command_text="$2" status; say cmd "$description"; if is_dry_run; then printf '    DRY-RUN shell: %s\n' "$command_text"; say ok "$description simulado pelo dry-run"; return 0; fi; set +e; bash -lc "$command_text" 2>&1 | while IFS= read -r line_out; do printf '    %s\n' "$line_out"; done; status=${PIPESTATUS[0]}; set -e; if ((status==0)); then say ok "$description concluído"; else say fail "$description falhou com código $status"; fi; return "$status"; }
clean_known_dirs(){ local label="$1" target found=0; shift; for target in "$@"; do [[ -e "$target" ]] || continue; found=1; remove_tree_guarded "$target" "$label" || true; done; ((found)) || say ok "Nenhum alvo encontrado para $label"; }

ACTION_IDS=(); ACTION_TITLES=(); ACTION_GROUPS=(); ACTION_RISKS=(); ACTION_DESCS=(); ACTION_ICONS=(); ACTIONS_INITIALIZED=false
register_action(){ ACTION_IDS+=("$1"); ACTION_TITLES+=("$2"); ACTION_GROUPS+=("$3"); ACTION_RISKS+=("$4"); ACTION_DESCS+=("$5"); ACTION_ICONS+=("$6"); }
init_actions(){ [[ "$ACTIONS_INITIALIZED" == true ]] && return 0; ACTION_IDS=(); ACTION_TITLES=(); ACTION_GROUPS=(); ACTION_RISKS=(); ACTION_DESCS=(); ACTION_ICONS=();
    register_action health_overview "Diagnóstico geral" "Diagnóstico" "leitura" "Mostra distro, kernel, disco, memória, uptime e Docker se existir." "$ICON_HEALTH"
    register_action sudo_refresh "Validar sudo" "Admin" "admin" "Verifica se o sudo sem prompt está em cache para ações Web." "$ICON_LOCK"
    register_action apt_update "Atualizar índices APT" "APT e pacotes" "admin" "Executa apt-get update não interativo com verificação de lock." "$ICON_PACKAGE"
    register_action apt_repair "Reparar APT/DPKG" "APT e pacotes" "admin" "Executa dpkg --configure -a e apt-get install -f -y." "🧩"
    register_action apt_upgrade "Atualizar pacotes" "APT e pacotes" "admin" "Executa apt-get upgrade -y com opções não interativas." "$ICON_PACKAGE"
    register_action apt_cleanup "Limpar cache APT" "APT e pacotes" "admin" "Executa autoremove, autoclean, clean e remove downloads parciais." "$ICON_BROOM"
    register_action tmp_cleanup "Limpar temporários seguros" "Limpeza segura" "seguro" "Remove entradas antigas de /tmp e /var/tmp com filtros de idade." "$ICON_BROOM"
    register_action user_cache_old "Limpar cache antigo do usuário" "Limpeza segura" "seguro" "Remove arquivos em ~/.cache com mais de 30 dias." "$ICON_BROOM"
    register_action thumbnails_cleanup "Limpar miniaturas" "Limpeza segura" "seguro" "Esvazia ~/.cache/thumbnails." "🖼️"
    register_action trash_cleanup "Esvaziar lixeira Linux" "Limpeza segura" "seguro" "Esvazia ~/.local/share/Trash/files e info." "🗑️"
    register_action font_cache "Reconstruir cache de fontes" "Limpeza segura" "seguro" "Remove cache fontconfig do usuário e roda fc-cache quando disponível." "🔤"
    register_action pip_cache "Limpar cache pip" "Dev caches" "seguro" "Executa python3 -m pip cache purge e pip3 cache purge quando disponíveis." "$ICON_CODE"
    register_action node_cache "Limpar cache Node" "Dev caches" "seguro" "Executa npm/yarn/pnpm cache clean/prune quando disponíveis." "$ICON_CODE"
    register_action python_modern_cache "Limpar caches Python modernos" "Dev caches" "seguro" "Limpa uv, pipx, pipenv, pdm, hatch e rye quando existirem." "$ICON_CODE"
    register_action java_cache "Limpar caches Java seguros" "Dev caches" "seguro" "Remove caches Gradle regeneráveis e metadados temporários Maven." "$ICON_CODE"
    register_action go_rust_cache "Limpar caches Go/Rust" "Dev caches" "seguro" "Executa go clean e remove caches seguros do Cargo." "$ICON_CODE"
    register_action composer_dotnet_cache "Limpar Composer/.NET" "Dev caches" "seguro" "Executa composer clear-cache e dotnet nuget locals all --clear." "$ICON_CODE"
    register_action browser_safe_cache "Limpar cache seguro de navegadores" "Apps e navegadores" "seguro" "Remove caches regeneráveis de navegadores quando fechados." "$ICON_BROWSER"
    register_action browser_advanced_cache "Limpar cache avançado de navegadores" "Apps e navegadores" "atenção" "Remove Service Worker CacheStorage, blob_storage e File System regeneráveis." "$ICON_BROWSER"
    register_action electron_ide_cache "Limpar IDEs/Electron" "Apps e navegadores" "seguro" "Remove caches regeneráveis de VS Code, VSCodium, JetBrains, Discord, Slack e similares." "🧠"
    register_action gpu_shader_cache "Limpar shader/GPU cache" "Apps e navegadores" "seguro" "Remove caches Mesa, Vulkan, NVIDIA ComputeCache e GPUCache regeneráveis." "$ICON_GPU"
    register_action virtualenv_preview "Preview de ambientes virtuais" "Regeneráveis" "leitura" "Lista venv/.venv/env/.tox/.nox sob HOME sem apagar." "🐍"
    register_action virtualenv_cleanup "Remover ambientes virtuais regeneráveis" "Regeneráveis" "alto" "Remove venv/.venv/env/.tox/.nox sob HOME com confirmação." "🐍"
    register_action node_modules_preview "Preview node_modules antigos" "Regeneráveis" "leitura" "Lista node_modules antigos com package.json irmão sem apagar." "🟩"
    register_action node_modules_cleanup "Remover node_modules antigos" "Regeneráveis" "alto" "Remove node_modules antigos com package.json irmão com confirmação." "🟩"
    register_action docker_status "Diagnóstico Docker" "Docker" "leitura" "Mostra docker system df quando daemon estiver ativo." "$ICON_DOCKER"
    register_action docker_audit "Página de auditoria Docker" "Docker" "leitura" "Executa auditoria detalhada Docker: version, context, df, ps, images e volumes." "$ICON_DOCKER"
    register_action docker_safe_prune "Docker seguro" "Docker" "seguro" "Executa builder prune e network prune sem apagar imagens/containers." "$ICON_DOCKER"
    register_action docker_destructive_prune "Docker destrutivo" "Docker" "alto" "Executa docker system prune -a -f com confirmação APAGAR-DOCKER." "$ICON_DOCKER"
    register_action node_python_audit "Página Node/Python" "Node/Python" "leitura" "Auditoria dedicada de versões, caches e gerenciadores Node/Python." "$ICON_CODE"
    register_action snap_flatpak "Atualizar Snap/Flatpak" "Pacotes universais" "admin" "Atualiza Snap/Flatpak e remove revisões/runtimes sem prompts interativos." "🧊"
    register_action journal_cleanup "Limpar Journal/crash" "Sistema" "admin" "Executa journalctl --vacuum-time=3d e limpa /var/crash." "🧾"
    register_action performance_session "Performance da sessão WSL2" "Sistema" "admin" "Ajusta sysctl de sessão, drop_caches e fstrim." "$ICON_SPEED"
    register_action wsl_diagnostics "Diagnóstico WSL2" "Diagnóstico" "leitura" "Mostra integração WSL, Windows interop, wsl.conf e kernel." "$ICON_WSL"
    register_action network_dns_audit "Auditoria DNS/rede" "Diagnóstico" "leitura" "Mostra resolv.conf, rotas, hosts e teste DNS leve." "🌐"
    register_action mounts_audit "Auditoria de mounts" "Diagnóstico" "leitura" "Mostra mounts relevantes, /mnt e filesystem root." "$ICON_DISK"
    register_action apt_sources_audit "Auditoria sources APT" "Diagnóstico" "leitura" "Lista sources.list e sources.list.d sem alterar nada." "$ICON_PACKAGE"
    register_action largest_offenders "Maiores ofensores em HOME" "Diagnóstico" "leitura" "Lista maiores diretórios e arquivos em HOME sem apagar." "$ICON_DISK"
    register_action reclaim_estimate "Estimativa recuperável" "Diagnóstico" "leitura" "Estima tamanho de caches conhecidos sem apagar." "$ICON_DISK"
    register_action export_temp_report "Exportar relatório temporário" "Relatórios" "leitura" "Cria relatório em /tmp somente quando o usuário pedir esta ação." "$ICON_REPORT"
    register_action history_hint "Histórico da sessão" "Relatórios" "leitura" "Explica que o histórico Web é mantido em memória por sessão no painel." "$ICON_HISTORY"
    register_action i18n_status "Internacionalização do painel" "Relatórios" "leitura" "Mostra suporte PT-BR/EN por toggle local no painel, sem alterar o idioma padrão pt-BR." "🌍"
    register_action all_safe "Executar pacote seguro" "Execução em lote" "lote" "Executa diagnóstico, APT repair/update/cleanup, temporários, caches dev e Docker seguro." "$ICON_SHIELD"
    register_action all_fast "Executar turbo seguro" "Execução em lote" "lote" "Executa conjunto rápido seguro, sem varreduras longas e sem destrutivos." "$ICON_STAR"
    register_action all_complete "Executar tudo com pop-up" "Execução em lote" "alto" "Executa roteiro completo real; destrutivos só entram com confirmação explícita." "🚨"
    ACTIONS_INITIALIZED=true
}
json_escape(){ local s="$1"; s="${s//\\/\\\\}"; s="${s//\"/\\\"}"; s="${s//$'\n'/\\n}"; s="${s//$'\r'/}"; printf '%s' "$s"; }
list_actions_json(){ init_actions; local i comma=""; printf '['; for ((i=0;i<${#ACTION_IDS[@]};i++)); do printf '%s{"id":"%s","number":%d,"title":"%s","group":"%s","risk":"%s","description":"%s","icon":"%s"}' "$comma" "$(json_escape "${ACTION_IDS[$i]}")" "$((i+1))" "$(json_escape "${ACTION_TITLES[$i]}")" "$(json_escape "${ACTION_GROUPS[$i]}")" "$(json_escape "${ACTION_RISKS[$i]}")" "$(json_escape "${ACTION_DESCS[$i]}")" "$(json_escape "${ACTION_ICONS[$i]}")"; comma=','; done; printf ']\n'; }
action_id_from_number(){ init_actions; local n="$1"; [[ "$n" =~ ^[0-9]+$ ]] || return 1; ((n>=1 && n<=${#ACTION_IDS[@]})) || return 1; printf '%s' "${ACTION_IDS[$((n-1))]}"; }
action_risk(){ init_actions; local id="$1" i; for ((i=0;i<${#ACTION_IDS[@]};i++)); do [[ "${ACTION_IDS[$i]}" == "$id" ]] && { printf '%s' "${ACTION_RISKS[$i]}"; return 0; }; done; return 1; }
action_title(){ init_actions; local id="$1" i; for ((i=0;i<${#ACTION_IDS[@]};i++)); do [[ "${ACTION_IDS[$i]}" == "$id" ]] && { printf '%s' "${ACTION_TITLES[$i]}"; return 0; }; done; printf '%s' "$id"; }
is_readonly_action(){ local risk; risk="$(action_risk "$1" 2>/dev/null || true)"; [[ "$risk" == "leitura" ]]; }

dry_run_action(){ local id="$1"; say warn "DRY-RUN global ativo para: $(action_title "$id")"; say warn "Nenhuma alteração será feita. O painel registrará métricas antes/depois sem executar comandos mutáveis."; case "$id" in virtualenv_cleanup) step_virtualenv_preview;; node_modules_cleanup) step_node_modules_preview;; docker_destructive_prune|docker_safe_prune|docker_status) step_docker_audit;; node_cache|pip_cache|python_modern_cache|node_python_audit) step_node_python_audit;; all_complete|all_safe|all_fast) echo "Plano de execução do lote em dry-run:"; echo "- Diagnósticos somente leitura podem ser executados."; echo "- APT, limpezas, Docker, Snap/Flatpak, Journal e performance seriam bloqueados."; echo "- Use o console para revisar a intenção antes de desativar dry-run.";; *) echo "Ação bloqueada pelo dry-run por possuir risco administrativo, seguro, atenção, lote ou alto."; echo "ID: $id"; echo "Título: $(action_title "$id")";; esac; }

# Ações reais
step_health_overview(){ say ok "Diagnóstico geral somente leitura"; printf 'Distro: %s\n' "$(grep '^PRETTY_NAME=' /etc/os-release 2>/dev/null|cut -d= -f2-|tr -d '"' || echo desconhecida)"; printf 'Kernel: %s\n' "$(uname -r 2>/dev/null || echo desconhecido)"; printf 'HOME alvo: %s\n' "$HOME"; printf 'Uptime: %s\n' "$(uptime -p 2>/dev/null || echo desconhecido)"; echo; df -h /; echo; free -h || true; echo; if command -v docker >/dev/null 2>&1 && docker info >/dev/null 2>&1; then docker system df; else echo 'Docker: indisponível ou daemon parado.'; fi; }
step_sudo_refresh(){ if [[ "${EUID}" -eq 0 ]]; then say ok "Executando como root."; return 0; fi; if sudo -n -v >/dev/null 2>&1; then say ok "sudo já está em cache sem prompt."; else say fail "sudo não está em cache para o painel Web. Rode no terminal: sudo -v"; return 1; fi; }
apt_y_opts=(-y -o Dpkg::Options::=--force-confdef -o Dpkg::Options::=--force-confold)
step_apt_update(){ check_apt_lock || return 1; run_external "Atualizando índices APT" sudo_run apt-get update; }
step_apt_repair(){ check_apt_lock || return 1; run_external "Reconfigurando DPKG" sudo_run dpkg --configure -a; run_external "Reparando dependências APT" sudo_run apt-get install -f "${apt_y_opts[@]}"; }
step_apt_upgrade(){ check_apt_lock || return 1; run_external "Atualizando pacotes APT" sudo_run apt-get upgrade "${apt_y_opts[@]}"; }
step_apt_cleanup(){ check_apt_lock || return 1; run_external "Removendo pacotes órfãos" sudo_run apt-get autoremove --purge "${apt_y_opts[@]}"; run_external "Autoclean APT" sudo_run apt-get autoclean -y; run_external "Clean APT" sudo_run apt-get clean; if [[ -d /var/cache/apt/archives/partial ]]; then if is_dry_run; then say warn "DRY-RUN: limparia /var/cache/apt/archives/partial"; else sudo_run find /var/cache/apt/archives/partial -mindepth 1 -ignore_readdir_race -exec rm -rf -- {} + 2>/dev/null || true; fi; fi; say ok "Limpeza APT finalizada."; }
step_tmp_cleanup(){ if is_dry_run; then say warn "DRY-RUN: removeria entradas antigas de /tmp (+1 dia) e /var/tmp (+7 dias)."; return 0; fi; sudo_run find /tmp -mindepth 1 -xdev -ignore_readdir_race -mtime +1 -exec rm -rf -- {} + 2>/dev/null || true; sudo_run find /var/tmp -mindepth 1 -xdev -ignore_readdir_race -mtime +7 -exec rm -rf -- {} + 2>/dev/null || true; say ok "Temporários antigos limpos."; }
