step_composer_dotnet_cache(){ command -v composer >/dev/null 2>&1 && run_external "Limpando cache Composer" composer clear-cache || say warn "Composer não instalado."; command -v dotnet >/dev/null 2>&1 && run_external "Limpando NuGet/.NET" dotnet nuget locals all --clear || say warn ".NET não instalado."; }
step_browser_safe_cache(){ if process_active chrome google-chrome chromium chromium-browser brave brave-browser msedge microsoft-edge firefox librewolf waterfox floorp zen; then say warn "Navegador aberto detectado; limpeza segura ignorada para evitar corrupção."; return 0; fi; clean_known_dirs "cache navegador" "$HOME/.cache/google-chrome" "$HOME/.cache/chromium" "$HOME/.cache/microsoft-edge" "$HOME/.cache/BraveSoftware/Brave-Browser" "$HOME/.cache/mozilla/firefox" "$HOME/.cache/librewolf"; }
step_browser_advanced_cache(){ if process_active chrome google-chrome chromium chromium-browser brave brave-browser msedge microsoft-edge firefox librewolf waterfox floorp zen; then say warn "Navegador aberto detectado; limpeza avançada ignorada."; return 0; fi; local base; for base in "$HOME/.config/google-chrome" "$HOME/.config/chromium" "$HOME/.config/microsoft-edge" "$HOME/.config/BraveSoftware/Brave-Browser"; do [[ -d "$base" ]] || continue; find "$base" -type d \( -name 'CacheStorage' -o -name 'ScriptCache' -o -name 'blob_storage' -o -name 'GPUCache' -o -name 'DawnCache' \) -prune -print0 2>/dev/null | while IFS= read -r -d '' d; do remove_tree_guarded "$d" "cache avançado navegador" || true; done; done; say ok "Cache avançado de navegadores finalizado."; }
step_electron_ide_cache(){ clean_known_dirs "cache IDE/Electron" "$HOME/.config/Code/Cache" "$HOME/.config/Code/CachedData" "$HOME/.config/Code/Code Cache" "$HOME/.config/Code/GPUCache" "$HOME/.config/Code/DawnCache" "$HOME/.config/Code/CachedExtensionVSIXs" "$HOME/.config/Code/logs" "$HOME/.config/Code/User/workspaceStorage" "$HOME/.config/VSCodium/Cache" "$HOME/.config/VSCodium/CachedData" "$HOME/.config/VSCodium/Code Cache" "$HOME/.config/VSCodium/GPUCache" "$HOME/.cache/JetBrains" "$HOME/.cache/discord" "$HOME/.cache/Discord" "$HOME/.cache/Slack" "$HOME/.cache/slack" "$HOME/.cache/obsidian" "$HOME/.cache/TelegramDesktop"; }
step_gpu_shader_cache(){ clean_known_dirs "cache shader/GPU" "$HOME/.cache/mesa_shader_cache" "$HOME/.cache/mesa_shader_cache_db" "$HOME/.cache/vulkan" "$HOME/.nv/ComputeCache" "$HOME/GPUCache"; }
find_virtualenvs(){ find "$HOME" -xdev \( -path "$HOME/.cache" -o -path "$HOME/.local/share/Trash" -o -path "$HOME/snap" -o -path "$HOME/.var" \) -prune -o -type d \( -name 'venv' -o -name '.venv' -o -name 'env' -o -name '.env' -o -name '.tox' -o -name '.nox' \) -prune -print0 2>/dev/null | while IFS= read -r -d '' d; do if [[ -f "$d/pyvenv.cfg" || -f "$d/bin/activate" || -d "$d/lib" || "$(basename "$d")" == ".tox" || "$(basename "$d")" == ".nox" ]]; then printf '%s\0' "$d"; fi; done; }
step_virtualenv_preview(){ say ok "Preview de ambientes virtuais sob HOME; nada será apagado."; local count=0 total=0 size d; while IFS= read -r -d '' d; do size="$(path_size_kb "$d")"; total=$((total+size)); count=$((count+1)); printf '%8s  %s\n' "$(format_kb "$size")" "$d"; done < <(find_virtualenvs); printf '\nEncontrados: %d | Estimado: %s\n' "$count" "$(format_kb "$total")"; }
step_virtualenv_cleanup(){ [[ "${SYSTEM_CARE_PRO_CONFIRM_DELETE:-}" == "APAGAR-REGENERAVEIS" ]] || { say fail "Confirmação ausente. Exige SYSTEM_CARE_PRO_CONFIRM_DELETE=APAGAR-REGENERAVEIS."; return 1; }; local d removed=0; while IFS= read -r -d '' d; do remove_tree_guarded "$d" "ambiente virtual" && removed=$((removed+1)); done < <(find_virtualenvs); say ok "Ambientes virtuais removidos: $removed"; }
find_node_modules_old(){ find "$HOME" -xdev -type d -name node_modules -prune -mtime +21 -print0 2>/dev/null | while IFS= read -r -d '' d; do [[ -f "$(dirname "$d")/package.json" ]] && printf '%s\0' "$d"; done; }
step_node_modules_preview(){ say ok "Preview node_modules antigos; nada será apagado."; local count=0 total=0 size d; while IFS= read -r -d '' d; do size="$(path_size_kb "$d")"; total=$((total+size)); count=$((count+1)); printf '%8s  %s\n' "$(format_kb "$size")" "$d"; done < <(find_node_modules_old); printf '\nEncontrados: %d | Estimado: %s\n' "$count" "$(format_kb "$total")"; }
step_node_modules_cleanup(){ [[ "${SYSTEM_CARE_PRO_CONFIRM_DELETE:-}" == "APAGAR-REGENERAVEIS" ]] || { say fail "Confirmação ausente. Exige SYSTEM_CARE_PRO_CONFIRM_DELETE=APAGAR-REGENERAVEIS."; return 1; }; local d removed=0; while IFS= read -r -d '' d; do remove_tree_guarded "$d" "node_modules" && removed=$((removed+1)); done < <(find_node_modules_old); say ok "node_modules removidos: $removed"; }
step_docker_status(){ if command -v docker >/dev/null 2>&1 && docker info >/dev/null 2>&1; then run_external "Uso Docker" docker system df; else say warn "Docker não está disponível ou daemon parado."; fi; }
step_docker_audit(){ say ok "Auditoria Docker dedicada"; if ! command -v docker >/dev/null 2>&1; then echo "Docker CLI não instalado."; return 0; fi; if ! docker info >/dev/null 2>&1; then echo "Docker daemon não está ativo ou não está acessível."; return 0; fi; echo "== docker version =="; docker version || true; echo; echo "== docker context ls =="; docker context ls || true; echo; echo "== docker system df -v =="; docker system df -v || true; echo; echo "== containers =="; docker ps -a --size || true; echo; echo "== images =="; docker images || true; echo; echo "== volumes =="; docker volume ls || true; echo; echo "== networks =="; docker network ls || true; }
step_docker_safe_prune(){ if command -v docker >/dev/null 2>&1 && docker info >/dev/null 2>&1; then run_external "Docker builder prune" docker builder prune -af; run_external "Docker network prune" docker network prune -f; else say warn "Docker indisponível."; fi; }
step_docker_destructive_prune(){ [[ "${SYSTEM_CARE_PRO_CONFIRM_DOCKER:-}" == "APAGAR-DOCKER" ]] || { say fail "Confirmação ausente. Exige SYSTEM_CARE_PRO_CONFIRM_DOCKER=APAGAR-DOCKER."; return 1; }; if command -v docker >/dev/null 2>&1 && docker info >/dev/null 2>&1; then run_external "Docker system prune -a" docker system prune -a -f; else say warn "Docker indisponível."; fi; }
step_node_python_audit(){ say ok "Auditoria dedicada Node/Python"; echo "== Python =="; command -v python3 >/dev/null 2>&1 && python3 --version || echo "python3 ausente"; command -v pip3 >/dev/null 2>&1 && pip3 --version || echo "pip3 ausente"; for bin in uv pipx pipenv poetry pdm hatch conda; do command -v "$bin" >/dev/null 2>&1 && printf '%-10s %s\n' "$bin" "$($bin --version 2>/dev/null | head -1)" || true; done; echo; echo "== Node =="; command -v node >/dev/null 2>&1 && node --version || echo "node ausente"; command -v npm >/dev/null 2>&1 && npm --version || echo "npm ausente"; for bin in yarn pnpm bun deno corepack; do command -v "$bin" >/dev/null 2>&1 && printf '%-10s %s\n' "$bin" "$($bin --version 2>/dev/null | head -1)" || true; done; echo; echo "== Caches conhecidos =="; step_reclaim_estimate; }
step_snap_flatpak(){ if command -v snap >/dev/null 2>&1; then run_external "Atualizando Snap sem prompt" sudo_run snap refresh; say cmd "Removendo revisões Snap desabilitadas sem prompt"; if is_dry_run; then snap list --all 2>/dev/null | awk '/disabled/{print "    DRY-RUN snap remove --purge "$1" --revision=" $3}' || true; else snap list --all 2>/dev/null | awk '/disabled/{print $1" "$3}' | while read -r s r; do [[ -n "$s" && -n "$r" ]] || continue; printf 'y\n' | sudo_run snap remove --purge "$s" --revision="$r" 2>&1 | while IFS= read -r line_out; do printf '    %s\n' "$line_out"; done || true; done; fi; else say warn "Snap não instalado."; fi; if command -v flatpak >/dev/null 2>&1; then run_external "Atualizando Flatpak sem prompt" flatpak update --noninteractive -y; run_external "Removendo Flatpaks não usados sem prompt" flatpak uninstall --unused --noninteractive -y; else say warn "Flatpak não instalado."; fi; }
step_journal_cleanup(){ command -v journalctl >/dev/null 2>&1 && run_external "Reduzindo Journal para 3 dias" sudo_run journalctl --vacuum-time=3d || say warn "journalctl indisponível."; if [[ -d /var/crash ]]; then if is_dry_run; then say warn "DRY-RUN: limparia /var/crash"; else sudo_run find /var/crash -mindepth 1 -ignore_readdir_race -exec rm -rf -- {} + 2>/dev/null || true; fi; fi; say ok "Journal/crash finalizado."; }
step_performance_session(){ sync || true; run_external "Ajustando vm.swappiness=10" sudo_run sysctl -w vm.swappiness=10 || true; run_external "Ajustando vm.vfs_cache_pressure=50" sudo_run sysctl -w vm.vfs_cache_pressure=50 || true; run_external "Ajustando dirty ratios" sudo_run sysctl -w vm.dirty_ratio=10 vm.dirty_background_ratio=5 || true; run_external "Liberando pagecache/dentries/inodes" sudo_run sh -c 'echo 3 > /proc/sys/vm/drop_caches' || true; command -v fstrim >/dev/null 2>&1 && run_external "Executando fstrim" sudo_run fstrim -av || true; }
step_wsl_diagnostics(){ printf 'WSL_DISTRO_NAME=%s\n' "${WSL_DISTRO_NAME:-não informado}"; printf 'Kernel=%s\n' "$(uname -r)"; command -v powershell.exe >/dev/null 2>&1 && echo 'powershell.exe disponível no PATH WSL.' || echo 'powershell.exe não detectado.'; [[ -f /etc/wsl.conf ]] && { echo; echo '/etc/wsl.conf:'; sed -n '1,160p' /etc/wsl.conf; } || echo '/etc/wsl.conf ausente.'; }
