step_mounts_audit(){ echo 'Filesystem root:'; df -h /; echo; echo 'Mounts WSL/mnt:'; mount | grep -E 'drvfs|wsl|/mnt|type ext4' || true; echo; ls -la /mnt 2>/dev/null || true; }
step_apt_sources_audit(){ echo '/etc/apt/sources.list:'; sed -n '1,220p' /etc/apt/sources.list 2>/dev/null || true; echo; echo 'sources.list.d:'; find /etc/apt/sources.list.d -maxdepth 1 -type f -print -exec sed -n '1,120p' {} \; 2>/dev/null || true; }
step_largest_offenders(){ echo 'Maiores diretórios em HOME:'; du -h --max-depth=1 "$HOME" 2>/dev/null | sort -rh | head -30 || true; echo; echo 'Maiores arquivos em HOME:'; find "$HOME" -xdev -type f -printf '%s\t%p\n' 2>/dev/null | sort -rn | head -30 | awk '{printf "%.1f MB\t%s\n",$1/1024/1024,$2}' || true; }
step_reclaim_estimate(){ local total=0 size target; for target in "$HOME/.cache" "$HOME/.cache/thumbnails" "$HOME/.local/share/Trash" "$HOME/.npm" "$HOME/.cache/pip" "$HOME/.gradle/caches" "$HOME/.cargo/registry/cache" "$HOME/.cache/uv" "$HOME/.config/Code/Cache"; do size="$(path_size_kb "$target")"; total=$((total+size)); printf '%8s  %s\n' "$(format_kb "$size")" "$target"; done; printf '\nEstimativa bruta de caches conhecidos: %s\n' "$(format_kb "$total")"; }
step_export_temp_report(){ local report; report="$(mktemp /tmp/system-care-pro-wsl2-report.XXXXXX.md)"; { printf '# System Care Pro WSL2 — relatório temporário\n\n'; printf '- Gerado em: %s\n' "$(date -Is)"; printf '- Versão: %s\n' "$SCRIPT_VERSION"; printf '- HOME alvo: %s\n' "$HOME"; printf '- Kernel: %s\n' "$(uname -r)"; printf '\n## Diagnóstico\n\n'; step_health_overview; printf '\n## Estimativa recuperável\n\n'; step_reclaim_estimate; printf '\n## Ações cadastradas\n\n'; menu_preview; } > "$report"; chmod 600 "$report" 2>/dev/null || true; say ok "Relatório temporário criado somente por solicitação do usuário."; printf 'Arquivo: %s\n' "$report"; }
