step_all_complete(){ [[ "${SYSTEM_CARE_PRO_CONFIRM_ALL:-}" == "EXECUTAR-TUDO" ]] || { say fail "Confirmação ausente. Exige SYSTEM_CARE_PRO_CONFIRM_ALL=EXECUTAR-TUDO."; return 1; }; say warn "Execução completa iniciada por confirmação explícita."; run_batch_step "Diagnóstico geral" step_health_overview; run_batch_step "Diagnóstico WSL2" step_wsl_diagnostics; run_batch_step "Auditoria DNS/rede" step_network_dns_audit; run_batch_step "Auditoria mounts" step_mounts_audit; run_batch_step "Auditoria sources APT" step_apt_sources_audit; run_batch_step "Auditoria Docker" step_docker_audit; run_batch_step "Auditoria Node/Python" step_node_python_audit; run_batch_step "Maiores ofensores" step_largest_offenders; run_batch_step "Estimativa recuperável" step_reclaim_estimate; run_batch_step "Validar sudo" step_sudo_refresh; run_batch_step "Reparar APT/DPKG" step_apt_repair; run_batch_step "Atualizar índices APT" step_apt_update; run_batch_step "Atualizar pacotes" step_apt_upgrade; run_batch_step "Limpar cache APT" step_apt_cleanup; run_batch_step "Temporários" step_tmp_cleanup; run_batch_step "Cache usuário" step_user_cache_old; run_batch_step "Miniaturas" step_thumbnails_cleanup; run_batch_step "Lixeira" step_trash_cleanup; run_batch_step "Fonte" step_font_cache; run_batch_step "Pip" step_pip_cache; run_batch_step "Node" step_node_cache; run_batch_step "Python moderno" step_python_modern_cache; run_batch_step "Java" step_java_cache; run_batch_step "Go/Rust" step_go_rust_cache; run_batch_step "Composer/.NET" step_composer_dotnet_cache; run_batch_step "Navegadores seguros" step_browser_safe_cache; run_batch_step "Navegadores avançados" step_browser_advanced_cache; run_batch_step "IDEs/Electron" step_electron_ide_cache; run_batch_step "Shader/GPU" step_gpu_shader_cache; run_batch_step "Preview venv" step_virtualenv_preview; [[ "${SYSTEM_CARE_PRO_CONFIRM_DELETE:-}" == "APAGAR-REGENERAVEIS" ]] && run_batch_step "Remover venv" step_virtualenv_cleanup || say warn "Ambientes virtuais não removidos sem APAGAR-REGENERAVEIS."; run_batch_step "Preview node_modules" step_node_modules_preview; [[ "${SYSTEM_CARE_PRO_CONFIRM_DELETE:-}" == "APAGAR-REGENERAVEIS" ]] && run_batch_step "Remover node_modules" step_node_modules_cleanup || say warn "node_modules não removidos sem APAGAR-REGENERAVEIS."; run_batch_step "Docker seguro" step_docker_safe_prune; [[ "${SYSTEM_CARE_PRO_CONFIRM_DOCKER:-}" == "APAGAR-DOCKER" ]] && run_batch_step "Docker destrutivo" step_docker_destructive_prune || say warn "Docker destrutivo não executado sem APAGAR-DOCKER."; run_batch_step "Snap/Flatpak" step_snap_flatpak; run_batch_step "Journal/crash" step_journal_cleanup; run_batch_step "Performance" step_performance_session; say ok "Execução completa finalizada."; }

run_action(){ local id="${1:-}"; case "$id" in "") say fail "Ação vazia."; return 127;; esac; if is_dry_run && ! is_readonly_action "$id"; then dry_run_action "$id"; return 0; fi; case "$id" in health_overview) step_health_overview;; sudo_refresh) step_sudo_refresh;; apt_update) step_apt_update;; apt_repair) step_apt_repair;; apt_upgrade) step_apt_upgrade;; apt_cleanup) step_apt_cleanup;; tmp_cleanup) step_tmp_cleanup;; user_cache_old) step_user_cache_old;; thumbnails_cleanup) step_thumbnails_cleanup;; trash_cleanup) step_trash_cleanup;; font_cache) step_font_cache;; pip_cache) step_pip_cache;; node_cache) step_node_cache;; python_modern_cache) step_python_modern_cache;; java_cache) step_java_cache;; go_rust_cache) step_go_rust_cache;; composer_dotnet_cache) step_composer_dotnet_cache;; browser_safe_cache) step_browser_safe_cache;; browser_advanced_cache) step_browser_advanced_cache;; electron_ide_cache) step_electron_ide_cache;; gpu_shader_cache) step_gpu_shader_cache;; virtualenv_preview) step_virtualenv_preview;; virtualenv_cleanup) step_virtualenv_cleanup;; node_modules_preview) step_node_modules_preview;; node_modules_cleanup) step_node_modules_cleanup;; docker_status) step_docker_status;; docker_audit) step_docker_audit;; docker_safe_prune) step_docker_safe_prune;; docker_destructive_prune) step_docker_destructive_prune;; node_python_audit) step_node_python_audit;; snap_flatpak) step_snap_flatpak;; journal_cleanup) step_journal_cleanup;; performance_session) step_performance_session;; wsl_diagnostics) step_wsl_diagnostics;; network_dns_audit) step_network_dns_audit;; mounts_audit) step_mounts_audit;; apt_sources_audit) step_apt_sources_audit;; largest_offenders) step_largest_offenders;; reclaim_estimate) step_reclaim_estimate;; export_temp_report) step_export_temp_report;; history_hint) step_history_hint;; i18n_status) step_i18n_status;; all_safe) step_health_overview; step_apt_repair; step_apt_update; step_apt_cleanup; step_tmp_cleanup; step_user_cache_old; step_thumbnails_cleanup; step_trash_cleanup; step_pip_cache; step_node_cache; step_python_modern_cache; step_browser_safe_cache; step_electron_ide_cache; step_gpu_shader_cache; step_docker_safe_prune;; all_fast) step_health_overview; step_tmp_cleanup; step_user_cache_old; step_thumbnails_cleanup; step_pip_cache; step_node_cache; step_browser_safe_cache; step_gpu_shader_cache; step_reclaim_estimate;; all_complete) step_all_complete;; *) say fail "Ação inexistente: $id"; return 127;; esac; }

cli_menu(){ init_actions; local choice id i current_group=""; while true; do line; printf '%b%s %s v%s — CLI estável%b\n' "$(c "$C_PRIMARY$BOLD")" "$ICON_SHIELD" "$SCRIPT_NAME" "$SCRIPT_VERSION" "$(ce)"; line; for ((i=0;i<${#ACTION_IDS[@]};i++)); do if [[ "${ACTION_GROUPS[$i]}" != "$current_group" ]]; then current_group="${ACTION_GROUPS[$i]}"; printf '\n  %b%s%b\n' "$(c "$C_SECONDARY$BOLD")" "$current_group" "$(ce)"; fi; printf '  %b%02d%b  %s  %-42s  %b[%s]%b\n' "$(c "$C_ACCENT")" "$((i+1))" "$(ce)" "${ACTION_ICONS[$i]}" "${ACTION_TITLES[$i]}" "$(c "$C_MUTED")" "${ACTION_RISKS[$i]}" "$(ce)"; done; printf '\n  %b00%b  %s  Sair\n\n' "$(c "$C_ERROR")" "$(ce)" "$ICON_EXIT"; printf '  Escolha: '; read -r choice; case "${choice,,}" in q|quit|exit|sair|s|0|00) say ok "Finalizado."; return 0;; esac; id="$(action_id_from_number "$choice" 2>/dev/null || true)"; [[ -n "$id" ]] || id="$choice"; line; say cmd "Executando: $id"; run_action "$id" || true; line; printf '  Pressione ENTER para voltar ao menu...'; read -r _; done; }
menu_preview(){ init_actions; local i; for ((i=0;i<${#ACTION_IDS[@]};i++)); do printf '%02d  %-30s  %s\n' "$((i+1))" "${ACTION_IDS[$i]}" "${ACTION_TITLES[$i]}"; done; }

launch_web_tui(){ require_python3; local port="${SYSTEM_CARE_PRO_PORT:-$DEFAULT_WEB_PORT}" script_path; script_path="$(readlink -f "${BASH_SOURCE[0]}" 2>/dev/null || printf '%s' "${BASH_SOURCE[0]}")"; export SYSTEM_CARE_PRO_SCRIPT="$script_path" SYSTEM_CARE_PRO_PORT_VALUE="$port"; python3 -u - <<'PYWEB'
import json, os, secrets, subprocess, sys, time, shutil, socket, threading, html
from http.server import BaseHTTPRequestHandler, ThreadingHTTPServer
from urllib.parse import urlparse, parse_qs

SCRIPT=os.environ.get('SYSTEM_CARE_PRO_SCRIPT')
PORT=int(os.environ.get('SYSTEM_CARE_PRO_PORT_VALUE','8787'))
TOKEN=secrets.token_urlsafe(24)
STARTED=time.time()
HISTORY=[]
MAX_HISTORY=250

def base_env(extra=None):
    env=os.environ.copy()
    env.update({'DEBIAN_FRONTEND':'noninteractive','APT_LISTCHANGES_FRONTEND':'none','NEEDRESTART_MODE':'a','SYSTEMD_PAGER':'cat','PAGER':'cat'})
    if extra: env.update(extra)
    return env

def command_for(args):
    stdbuf=shutil.which('stdbuf')
    return ([stdbuf,'-oL','-eL']+args) if stdbuf else args

def run_cmd(args,timeout=120,extra_env=None):
    try:
        p=subprocess.run(command_for(args),text=True,capture_output=True,timeout=timeout,env=base_env(extra_env))
        return {'ok':p.returncode==0,'code':p.returncode,'stdout':p.stdout,'stderr':p.stderr}
    except subprocess.TimeoutExpired as e:
        return {'ok':False,'code':124,'stdout':e.stdout or '', 'stderr':'Tempo esgotado.'}
    except Exception as e:
        return {'ok':False,'code':1,'stdout':'','stderr':str(e)}

def get_actions():
    r=run_cmd([SCRIPT,'--list-actions-json'],timeout=30)
    if not r['ok']: return []
    try: return json.loads(r['stdout'])
    except Exception: return []

def shell(cmd):
    try: return subprocess.run(cmd,shell=True,text=True,capture_output=True,timeout=8,env=base_env()).stdout.strip()
    except Exception: return ''

def metrics():
    disk_line=shell("df -P / | awk 'NR==2{print $3, $4, $5}'")
    mem_line=shell("free -m | awk '/Mem:/{print $3, $2}'")
    dused=dfree=dpct=mused=mtotal=mpct=0
    if disk_line:
        parts=disk_line.split()
        try: dused=int(parts[0]); dfree=int(parts[1]); dpct=int(parts[2].rstrip('%'))
        except Exception: pass
    if mem_line:
        parts=mem_line.split()
        try: mused=int(parts[0]); mtotal=int(parts[1]); mpct=int(mused*100/max(mtotal,1))
        except Exception: pass
    return {'diskUsedKb':dused,'diskFreeKb':dfree,'diskPct':dpct,'memUsedMb':mused,'memTotalMb':mtotal,'memPct':mpct}

def read_status():
    m=metrics(); distro=shell("grep '^PRETTY_NAME=' /etc/os-release | cut -d= -f2- | tr -d '\"'") or 'WSL2 Ubuntu'; kernel=shell('uname -r')
    wsl=bool(os.environ.get('WSL_DISTRO_NAME')) or 'microsoft' in shell('cat /proc/version 2>/dev/null').lower()
    sudo_cached=subprocess.run('sudo -n true',shell=True,stdout=subprocess.DEVNULL,stderr=subprocess.DEVNULL).returncode==0
    docker_active=subprocess.run('command -v docker >/dev/null 2>&1 && docker info >/dev/null 2>&1',shell=True,stdout=subprocess.DEVNULL,stderr=subprocess.DEVNULL).returncode==0
    seconds=int(time.time()-STARTED); h,rem=divmod(seconds,3600); mi,se=divmod(rem,60)
    return {'name':'System Care Pro WSL2','version':'9.0.0-webnova-roadmap','engine':'WebNova Roadmap TUI CSS','uptime':f'{h:02d}:{mi:02d}:{se:02d}','distro':distro,'kernel':kernel,'wsl':wsl,'sudoCached':sudo_cached,'dockerActive':docker_active,'time':time.strftime('%H:%M:%S'),**m}

def sse_send(handler,obj):
    data=json.dumps(obj,ensure_ascii=False)
    handler.wfile.write(f'data: {data}\n\n'.encode('utf-8'))
    handler.wfile.flush()

def run_stream(handler, action, flags):
    extra={}
    if flags.get('dryRun')=='1': extra['SYSTEM_CARE_PRO_DRY_RUN']='true'
    if flags.get('confirm')=='APAGAR-DOCKER': extra['SYSTEM_CARE_PRO_CONFIRM_DOCKER']='APAGAR-DOCKER'
    if flags.get('confirm')=='APAGAR-REGENERAVEIS': extra['SYSTEM_CARE_PRO_CONFIRM_DELETE']='APAGAR-REGENERAVEIS'
    if flags.get('confirm')=='EXECUTAR-TUDO': extra['SYSTEM_CARE_PRO_CONFIRM_ALL']='EXECUTAR-TUDO'
    if flags.get('includeRegen')=='1': extra['SYSTEM_CARE_PRO_CONFIRM_DELETE']='APAGAR-REGENERAVEIS'
    if flags.get('includeDocker')=='1': extra['SYSTEM_CARE_PRO_CONFIRM_DOCKER']='APAGAR-DOCKER'
    before=metrics(); started=time.time(); title=action
    history_item={'action':action,'startedAt':time.strftime('%Y-%m-%d %H:%M:%S'),'code':None,'durationSec':0,'before':before,'after':None,'dryRun':extra.get('SYSTEM_CARE_PRO_DRY_RUN')=='true'}
    sse_send(handler,{'type':'start','action':action,'before':before,'dryRun':history_item['dryRun']})
    try:
        p=subprocess.Popen(command_for([SCRIPT,'--run-action',action]),stdout=subprocess.PIPE,stderr=subprocess.STDOUT,text=True,bufsize=1,env=base_env(extra))
        assert p.stdout is not None
        for line in p.stdout:
            sse_send(handler,{'type':'line','text':line})
        code=p.wait()
    except BrokenPipeError:
        return
    except Exception as e:
        code=1; sse_send(handler,{'type':'line','text':'ERRO DO BACKEND: '+str(e)+'\n'})
    after=metrics(); duration=round(time.time()-started,2)
    history_item.update({'code':code,'durationSec':duration,'after':after})
    HISTORY.insert(0,history_item)
    del HISTORY[MAX_HISTORY:]
    sse_send(handler,{'type':'end','code':code,'ok':code==0,'after':after,'durationSec':duration})

