const token=new URLSearchParams(location.search).get('token')||'';let actions=[],running=false,lang=localStorage.getItem('scp_lang')||'pt';const $=s=>document.querySelector(s);const $$=s=>[...document.querySelectorAll(s)];function api(path,opts={}){const sep=path.includes('?')?'&':'?';return fetch(path+sep+'token='+encodeURIComponent(token),opts).then(r=>{if(!r.ok)throw new Error('HTTP '+r.status);return r.json()})}function log(t){const el=$('#console');el.textContent+=t;el.scrollTop=el.scrollHeight}function toast(t){const el=$('#toast');el.textContent=t;el.classList.add('show');setTimeout(()=>el.classList.remove('show'),2400)}function pct(n){return (Number(n)||0)+'%'}function setBar(v){$('#bar').style.width=Math.max(0,Math.min(100,v))+'%'}async function refresh(){const s=await api('/api/status');$('#diskPct').textContent=pct(s.diskPct);$('#memPct').textContent=pct(s.memPct);$('#sudoState').textContent=s.sudoCached?'OK':'Pedir';$('#dockerState').textContent=s.dockerActive?'Ativo':'Off';$('#uptime').textContent=s.uptime;renderHistory()}async function load(){actions=await api('/api/actions');render();renderSidebar();refresh();setInterval(refresh,8000)}function filtered(){const q=($('#search').value||$('#navSearch').value||'').toLowerCase();return actions.filter(a=>(a.title+a.group+a.description+a.id).toLowerCase().includes(q))}function render(){const el=$('#cards');el.innerHTML='';for(const a of filtered()){const card=document.createElement('article');card.className='card';card.onmousemove=e=>{const r=card.getBoundingClientRect();card.style.setProperty('--mx',((e.clientX-r.left)/r.width*100)+'%');card.style.setProperty('--my',((e.clientY-r.top)/r.height*100)+'%')};card.onclick=()=>runAction(a.id,a.risk);card.innerHTML=`<div class="card-head"><div class="card-icon">${a.icon}</div><div class="risk ${a.risk}">${a.risk}</div></div><h3>${String(a.number).padStart(2,'0')} • ${a.title}</h3><p>${a.description}</p>`;el.appendChild(card)}}function renderSidebar(){const el=$('#sidebarNav');el.innerHTML='';let group='';for(const a of filtered()){if(a.group!==group){group=a.group;const g=document.createElement('div');g.className='nav-title';g.textContent=group;el.appendChild(g)}const b=document.createElement('button');b.className='nav-item';b.onclick=()=>runAction(a.id,a.risk);b.innerHTML=`<small>${String(a.number).padStart(2,'0')}</small><span>${a.icon} ${a.title}</span><i class="dot ${a.risk}"></i>`;el.appendChild(b)}}function flagsFor(action,risk,opts={}){const p=new URLSearchParams({token,id:action});if($('#dryRun').checked||opts.dryRun)p.set('dryRun','1');if(opts.confirm)p.set('confirm',opts.confirm);if(opts.includeRegen)p.set('includeRegen','1');if(opts.includeDocker)p.set('includeDocker','1');return p}function runAction(action,risk,opts={}){if(running)return toast('Uma ação já está rodando.');if(action==='all_complete'&&!opts.confirm){openAll();return}let confirmText=opts.confirm||'';if(risk==='alto'&&!confirmText){if(action.includes('docker'))confirmText='APAGAR-DOCKER';else if(!confirm('Ação de alto impacto. Confirma executar?'))return;else confirmText='APAGAR-REGENERAVEIS'}const params=flagsFor(action,risk,{...opts,confirm:confirmText});running=true;setBar(8);$('#runState').textContent='Rodando';$('#consoleTitle').textContent='Executando '+action;log(`\n\n▶ ${action}\n`);const es=new EventSource('/api/run-stream?'+params.toString());es.onmessage=e=>{const data=JSON.parse(e.data);if(data.type==='start'){setBar(15);log(`Métricas antes: disco ${data.before.diskPct}% • memória ${data.before.memPct}%${data.dryRun?' • DRY-RUN':''}\n`)}if(data.type==='line'){log(data.text);setBar(45)}if(data.type==='end'){setBar(100);log(`\nMétricas depois: disco ${data.after.diskPct}% • memória ${data.after.memPct}%\nCódigo de saída: ${data.code} • duração: ${data.durationSec}s\n`);running=false;$('#runState').textContent='Pronto';$('#consoleTitle').textContent='Console real streaming';es.close();setTimeout(()=>setBar(0),900);refresh();toast(data.ok?'Ação concluída':'Ação retornou erro')}};es.onerror=()=>{log('\n[stream encerrado]\n');running=false;$('#runState').textContent='Pronto';es.close();refresh()}}async function renderHistory(){try{const hist=await api('/api/history');const el=$('#history');if(!hist.length){el.innerHTML='<p>Sem execuções nesta sessão.</p>';return}el.innerHTML='<div class="history-row"><b>Ação</b><b>Horário</b><b>Código</b><b>Duração</b><b>Métricas</b></div>'+hist.map(h=>`<div class="history-row"><span>${h.action}${h.dryRun?' • dry-run':''}</span><span>${h.startedAt}</span><span>${h.code}</span><span>${h.durationSec}s</span><span>D ${h.before.diskPct}%→${h.after.diskPct}% • M ${h.before.memPct}%→${h.after.memPct}%</span></div>`).join('')}catch(e){}}function openAll(){$('#allModal').classList.add('open');$('#allConfirm').focus()}function closeAll(){$('#allModal').classList.remove('open')}function setConsole(state){const b=$('#consoleBox');b.classList.remove('mini','max','hidden');$('#showConsole').classList.remove('visible');if(state==='mini')b.classList.add('mini');if(state==='max')b.classList.add('max');if(state==='hidden'){b.classList.add('hidden');$('#showConsole').classList.add('visible')}localStorage.setItem('scp_console_state',state)}$$('.tab').forEach(t=>t.onclick=()=>{$$('.panel').forEach(p=>p.classList.remove('active'));$('#page-'+t.dataset.page).classList.add('active')});$('#search').oninput=()=>{render();$('#navSearch').value=$('#search').value;renderSidebar()};$('#navSearch').oninput=()=>{$('#search').value=$('#navSearch').value;render();renderSidebar()};$('#refresh').onclick=refresh;$('#sudo').onclick=()=>runAction('sudo_refresh','admin');$('#runAll').onclick=openAll;$('#sideAll').onclick=openAll;$('#confirmAll').onclick=()=>{if($('#allConfirm').value.trim()!=='EXECUTAR-TUDO')return toast('Digite EXECUTAR-TUDO');closeAll();runAction('all_complete','alto',{confirm:'EXECUTAR-TUDO',includeRegen:$('#includeRegen').checked,includeDocker:$('#includeDocker').checked,dryRun:$('#modalDryRun').checked})};$('#cancelAll').onclick=closeAll;$('#allModal').onclick=e=>{if(e.target.id==='allModal')closeAll()};$('#density').onclick=()=>{document.body.classList.toggle('compact');localStorage.setItem('scp_compact',document.body.classList.contains('compact')?'1':'0')};$('#theme').onclick=$('#sideTheme').onclick=()=>{document.body.classList.toggle('light');localStorage.setItem('scp_theme',document.body.classList.contains('light')?'light':'dark')};$('#sideDry').onclick=()=>{$('#dryRun').checked=!$('#dryRun').checked;toast($('#dryRun').checked?'Dry-run ligado':'Dry-run desligado')};$('#minConsole').onclick=()=>setConsole($('#consoleBox').classList.contains('mini')?'normal':'mini');$('#maxConsole').onclick=()=>setConsole($('#consoleBox').classList.contains('max')?'normal':'max');$('#hideConsole').onclick=$('#sideConsole').onclick=()=>setConsole('hidden');$('#showConsole').onclick=()=>setConsole('normal');$('#clearConsole').onclick=()=>$('#console').textContent='Console limpo.\n';$('#copyConsole').onclick=()=>navigator.clipboard?.writeText($('#console').textContent).then(()=>toast('Console copiado.')).catch(()=>toast('Não foi possível copiar.'));$('#lang').onclick=()=>{lang=lang==='pt'?'en':'pt';localStorage.setItem('scp_lang',lang);toast(lang==='pt'?'Idioma: PT-BR':'Language: EN')};document.addEventListener('keydown',e=>{if((e.ctrlKey||e.metaKey)&&e.key.toLowerCase()==='k'){e.preventDefault();$('#search').focus()}if(e.key==='Escape'){closeAll();if($('#consoleBox').classList.contains('max'))setConsole('normal')}});if(localStorage.getItem('scp_compact')==='1')document.body.classList.add('compact');if(localStorage.getItem('scp_theme')==='light')document.body.classList.add('light');setConsole(localStorage.getItem('scp_console_state')||'normal');load().catch(e=>log('Falha ao iniciar UI: '+e.message+'\n'));
</script></body></html>'''

class Handler(BaseHTTPRequestHandler):
    server_version='SystemCareWebNova/9.0'
    def log_message(self,fmt,*args): return
    def authorized(self): return parse_qs(urlparse(self.path).query).get('token',[''])[0]==TOKEN
    def send_json(self,data,code=200):
        body=json.dumps(data,ensure_ascii=False).encode('utf-8'); self.send_response(code); self.send_header('Content-Type','application/json; charset=utf-8'); self.send_header('Content-Length',str(len(body))); self.end_headers(); self.wfile.write(body)
    def do_GET(self):
        path=urlparse(self.path).path; qs=parse_qs(urlparse(self.path).query)
        if path=='/':
            body=HTML.encode('utf-8'); self.send_response(200); self.send_header('Content-Type','text/html; charset=utf-8'); self.send_header('Content-Length',str(len(body))); self.end_headers(); self.wfile.write(body); return
        if not self.authorized(): self.send_json({'ok':False,'error':'token inválido'},403); return
        if path=='/api/actions': self.send_json(get_actions()); return
        if path=='/api/status': self.send_json(read_status()); return
        if path=='/api/history': self.send_json(HISTORY); return
        if path=='/api/run-stream':
            action=qs.get('id',[''])[0]
            flags={k:qs.get(k,[''])[0] for k in ['confirm','includeRegen','includeDocker','dryRun']}
            self.send_response(200); self.send_header('Content-Type','text/event-stream; charset=utf-8'); self.send_header('Cache-Control','no-cache'); self.send_header('X-Accel-Buffering','no'); self.end_headers(); run_stream(self,action,flags); return
        self.send_json({'ok':False,'error':'rota inexistente'},404)

def find_port(start):
    for p in [start]+list(range(start+1,start+30)):
        with socket.socket(socket.AF_INET,socket.SOCK_STREAM) as s:
            try: s.bind(('127.0.0.1',p)); return p
            except OSError: continue
    return 0
PORT=find_port(PORT)
server=ThreadingHTTPServer(('127.0.0.1',PORT),Handler)
url=f'http://127.0.0.1:{PORT}/?token={TOKEN}'
print('\n🌐 WebNova Roadmap TUI CSS iniciado com segurança local')
print(f'URL: {url}')
print('Bind: 127.0.0.1 | Console: streaming real | Histórico: memória | Ctrl+C para sair\n')
def opener():
    time.sleep(.6); cmds=[]
    if shutil.which('wslview'): cmds.append(['wslview',url])
    if shutil.which('explorer.exe'): cmds.append(['explorer.exe',url])
    if shutil.which('powershell.exe'): cmds.append(['powershell.exe','-NoProfile','-Command',f'Start-Process "{url}"'])
    for cmd in cmds:
        try: subprocess.Popen(cmd,stdout=subprocess.DEVNULL,stderr=subprocess.DEVNULL); return
        except Exception: pass
threading.Thread(target=opener,daemon=True).start()
try: server.serve_forever()
except KeyboardInterrupt: print('\nServidor WebNova encerrado.')
PYWEB
}

self_test(){ local errors=0 id case_body count lines; echo "Self-test do $SCRIPT_NAME v$SCRIPT_VERSION"; require_bash_version || errors=$((errors+1)); init_actions; count="${#ACTION_IDS[@]}"; if ((count<45)); then echo "FALHA: catálogo com poucas ações: $count"; errors=$((errors+1)); else echo "OK: catálogo possui $count ações reais."; fi; case_body="$(declare -f run_action)"; for id in "${ACTION_IDS[@]}"; do if ! grep -q "[;)[:space:]]$id)" <<< "$case_body" && ! grep -q "^.*$id)" <<< "$case_body"; then echo "FALHA: ação sem dispatcher: $id"; errors=$((errors+1)); fi; done; if grep -Eq '^[[:space:]]*eval[[:space:]]' "$0"; then echo "FALHA: eval detectado."; errors=$((errors+1)); else echo "OK: sem eval."; fi; if grep -Eq '^[^#]*(update-grub|grub-install|mkinitramfs)' "$0"; then echo "FALHA: GRUB/kernel detectado."; errors=$((errors+1)); else echo "OK: sem comandos GRUB/kernel."; fi; grep -q "text/event-stream" "$0" && echo "OK: console Web usa streaming SSE real." || { echo "FALHA: SSE não encontrado."; errors=$((errors+1)); }; grep -q -- "--noninteractive" "$0" && grep -q "snap remove --purge" "$0" && echo "OK: Snap/Flatpak sem prompts interativos." || { echo "FALHA: automação Snap/Flatpak incompleta."; errors=$((errors+1)); }; grep -q "SYSTEM_CARE_PRO_DRY_RUN" "$0" && echo "OK: dry-run global implementado." || { echo "FALHA: dry-run ausente."; errors=$((errors+1)); }; grep -Fq "HISTORY=[]" "$0" && echo "OK: histórico em memória por sessão implementado." || { echo "FALHA: histórico em memória ausente."; errors=$((errors+1)); }; grep -q "body.light" "$0" && echo "OK: tema claro opcional implementado." || { echo "FALHA: tema claro ausente."; errors=$((errors+1)); }; grep -q "docker_audit" "$0" && grep -q "node_python_audit" "$0" && echo "OK: páginas dedicadas Docker e Node/Python implementadas." || { echo "FALHA: auditorias dedicadas ausentes."; errors=$((errors+1)); }; grep -q "export_temp_report" "$0" && echo "OK: exportação opcional de relatório temporário implementada." || { echo "FALHA: relatório temporário ausente."; errors=$((errors+1)); }; grep -q "ThreadingHTTPServer(('127.0.0.1'" "$0" && echo "OK: servidor limitado a 127.0.0.1." || { echo "FALHA: bind local ausente."; errors=$((errors+1)); }; lines="$(wc -l < "$0"|awk '{print $1}')"; if ((lines<4000)); then echo "FALHA: menos de 4000 linhas: $lines"; errors=$((errors+1)); else echo "OK: script possui $lines linhas."; fi; if ((errors==0)); then echo "SELF-TEST OK"; return 0; fi; echo "SELF-TEST FALHOU com $errors erro(s)."; return 1; }
main(){ case "${1:-}" in --self-test) self_test; exit $?;; --list-actions-json) list_actions_json; exit 0;; --menu-preview) menu_preview; exit 0;; --run-action) shift; require_bash_version; require_wsl2_ubuntu; run_action "${1:-}"; exit $?;; --cli) require_bash_version; require_wsl2_ubuntu; cli_menu; exit $?;; --version|-v) printf '%s v%s\n' "$SCRIPT_NAME" "$SCRIPT_VERSION"; exit 0;; --help|-h) printf '%s v%s\nUso: %s [--cli|--self-test|--menu-preview|--run-action ID]\n' "$SCRIPT_NAME" "$SCRIPT_VERSION" "$0"; exit 0;; esac; require_bash_version; require_wsl2_ubuntu; require_python3; echo; say ok "Abrindo TUI Web CSS gráfico em 127.0.0.1."; say warn "Para ações admin no painel, rode antes no terminal: sudo -v"; launch_web_tui; }
main "$@"

